      "path": "src/modules/projects/service.js",
      "content": "const { generateId } = require('../../lib/id');
let projectsStore = [];

async function getAllProjects() {
  return projectsStore;
}

async function createProject(name) {
  if (projectsStore.some(p => p.name === name)) {
    throw new Error('PROJECT_ALREADY_EXISTS');
  }
  const project = { id: generateId(), name, tasks: [], members: [] };
  projectsStore.push(project);
  return project;
}

module.exports = {
  getAllProjects,
  createProject
};"
