      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  const { status } = req.query;
  try {
    const tasks = await tasksService.getTasks(req.params.projectId, status);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.post('/', async (req, res) => {
  const { title } = req.body;
  if (!title) {
    return sendError(res, 400, 'INVALID_INPUT', 'Title is required');
  }
  try {
    const task = await tasksService.createTask(req.params.projectId, title);
    res.status(201).json({ task });
  } catch (error) {
    if (error.code === 'PROJECT_NOT_FOUND') {
      return sendError(res, 404, 'PROJECT_NOT_FOUND', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

router.patch('/:taskId', async (req, res) => {
  const { status } = req.body;
  if (!status || ![ 'todo', 'done' ].includes(status)) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid status');
  }
  try {
    const task = await tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
    res.json({ task });
  } catch (error) {
    if (error.code === 'PROJECT_NOT_FOUND') {
      return sendError(res, 404, 'PROJECT_NOT_FOUND', error.message);
    }
    if (error.code === 'TASK_NOT_FOUND') {
      return sendError(res, 404, 'TASK_NOT_FOUND', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', error.message);
  }
});

module.exports = router;"
