    {
      "path": "src/modules/tasks/service.js",
      "content": "const { generateId } = require('../../lib/id');
let projectsStore = [];

async function createTask(projectId, title) {
  const project = projectsStore.find(p => p.id === projectId);
  if (!project) {
    throw new Error('PROJECT_NOT_FOUND');
  }
  const task = { id: generateId(), title, status: 'todo' };
  project.tasks.push(task);
  return task;
}

async function updateTaskStatus(projectId, taskId, status) {
  const project = projectsStore.find(p => p.id === projectId);
  if (!project) {
    throw new Error('PROJECT_NOT_FOUND');
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    throw new Error('TASK_NOT_FOUND');
  }
  task.status = status;
  return task;
}

async function getTasks(projectId, status) {
  const project = projectsStore.find(p => p.id === projectId);
  if (!project) {
    throw new Error('PROJECT_NOT_FOUND');
  }
  let tasks = project.tasks;
  if (status) {
    tasks = tasks.filter(t => t.status === status);
  }
  return tasks;
}

module.exports = {
  createTask,
  updateTaskStatus,
  getTasks
};"
