      "path": "src/modules/members/service.js",
      "content": "const { generateId } = require('../../lib/id');
let projectsStore = [];

async function addMember(projectId, userId, role) {
  const project = projectsStore.find(p => p.id === projectId);
  if (!project) {
    throw new Error('PROJECT_NOT_FOUND');
  }
  if (project.members.some(m => m.userId === userId)) {
    throw new Error('DUPLICATE_MEMBER');
  }
  const member = { id: generateId(), userId, role };
  project.members.push(member);
  return member;
}

module.exports = {
  addMember
};"
